INSERT INTO "announcements" ("id", "title", "content", "is_active", "created_at", "image_path") VALUES
    (3, 'SCHOLARSHIP CAMPUS CLEANING SCHEDULE', 'All scholars assigned to their designated areas at Davao Vision Colleges (DVC) are hereby reminded to take their responsibilities seriously and consistently.

Please be informed that performance, attendance, and compliance with assigned duties in your designated areas are official bases for the evaluation and renewal of your scholarship. Failure to perform your responsibilities properly, repeated absences, or neglect of duties may affect your eligibility for scholarship renewal.

This assignment is not optional—it is part of your scholarship agreement. We expect professionalism, accountability, and commitment from all scholars.

Let us all work together to uphold the standards of DVC and show gratitude for the opportunity given through the scholarship program.

For strict compliance.', 0, '2026-01-19 05:18:21', NULL);

INSERT INTO "scholarships" ("id", "name", "description", "deadline", "requirements", "application_requirements", "benefits", "available_slots", "category", "accepting_new_applicants", "accepting_renewal_applicants", "amount", "status", "created_at", "requires_exam", "passing_grade", "passing_score", "exam_duration", "end_of_term", "amount_type") VALUES
    (12, 'TEACHER''S WORKING STUDENT SCHOLARSHIP', 'The Teacher’s Working Students Scholarship aims to support the educational goals of students who are working for teachers. This scholarship acknowledges those working students and helps them achieve their academic endeavors.', '2026-04-30', 'Relationship Status:  The scholarship is must be the worker of the public or private teacher.

Academic Requirement: To be considered intellectually capable, the applicant must possess good academic standing with a general weighted average (85%)

Good Moral Character: Must have no record of major disciplinary offenses.', '1. Recommendation letter of her/his employer (PDF File)
2. Certificate of Employment (Provided by the employer) (PDF File)
3. Report Card/Transcript Records (Scan the report card front and back)
4. Certificate of Good Moral Character (PDF File)

Note: All required documents must be uploaded as clear, legible copies in PDF format.', 'The Teacher’s workers may enjoy 70% discounts on tuition fees equivalent to 21 units. If the student exceeds the maximum subject load per semester, he/she will shoulder the excess tuition fee.

Note: The tuition fee discount shall apply to tuition fees only and shall be effective for the applicable enrollment period, subject to institutional policies.', 10, 'Public teachers’ workers', 1, 0, '70.00', 'active', '2026-01-05 05:47:23', 0, 75, 75, 60, '2026-10-30', 'Percentage'),
    (13, 'ACADEMIC SCHOLARSHIP', 'An Academic Scholarship aims to support the educational goals of students based on their academic achievements and potential. This scholarship recognizes students who have demonstrated excellence in their studies, such as high grades and outstanding academic performance overall.', '2026-04-30', 'Academic Eligibility: 
      Must be an incoming or continuing student applying for an undergraduate program.
      Must have a strong academic record in the most recent level completed.

Academic Requirement: 
        For incoming students: Must have a minimum General weighted average of 93%
        For continuing students: General weighted average of at least 93% per semester, have no grade below 85% in any subject in throughout each semester.

Enrollment Status:
          Must enroll as a regular/full-time student in the semester the scholarship is awarded.
          Maintain a minimum standard of units based on the approved curriculum.

Good Moral Character:
          Must possess good moral character with no record of major disciplinary offense.
 
Non-Duplication of Major Scholarships:
         Must not be a recipient of another full tuition scholarship, unless otherwise approved by the institution.', 'New Applicant: 
1. Report Card/Transcript of Records (Scan the report card front and back)
2. Certification of Award (It should be indicated the number of graduates) (PDF File)
3. Certificate of Good Moral Character (PDF File)

Note: All required documents must be uploaded as clear, legible copies in PDF format.', 'A. New Students / Incoming First-Year Students
Graduates entering Davao Vision Colleges as incoming first-year students shall be entitled to tuition fee discounts based on their Senior High School academic honors, as follows:
With Highest Honors: 100% tuition fee discount
With High Honors:      70% tuition fee discount

B. Continuing Students
Students included in the Dean’s List shall be granted tuition fee discounts based on their departmental ranking or General Weighted Average (GWA) for the immediately preceding semester, in accordance with the following scheme:
Top 1 (per Department): 100% tuition fee discount
Top 2 (per Department): 70% tuition fee discount

The tuition fee discount shall apply to tuition fees only and shall be effective for the applicable enrollment period, subject to institutional policies.', 10, 'Student assistant', 1, 0, '100.00', 'active', '2026-01-05 07:33:58', 0, 75, 75, 60, '2026-10-30', 'Percentage'),
    (14, 'DVC SENIOR HIGH SCHOOL ALUMNI SCHOLARSHIP', 'The DVC Senior High School alumni scholarship is for a student who graduates from our institution and still chooses DVC for their studies in college. This scholarship recognizes students for their loyalty to their alma mater and also helps them achieve their academic endeavors.', '2026-04-30', 'Graduate of Davao Vision Colleges (DVC) Senior High School:  Must have completed Senior High School at DVC under any strand.

Academic Requirement: To be considered intellectually capable, the applicant must possess good academic standing with a general weighted average of at least 85%', '1. Report Card/Transcript Records (Scan the Report Card front and back)
2. Certificate of Graduation (PDF File)
3. Certificate of Low Income (PDF File)
4. Certificate of Good Moral Character (PDF File)
5. Certificate of Enrollment or Registration (PDF File)

Note: All required documents must be uploaded as clear, legible copies in PDF format.', 'The students may enjoy 70% discounts on tuition fees equivalent to 21 units. If the student exceeds the maximum subject load per semester, he/she will shoulder the excess tuition fee.

Note: The tuition fee discount shall apply to tuition fees only and shall be effective for the applicable enrollment period, subject to institutional policies.', 20, 'Student assistant', 1, 0, '70.00', 'active', '2026-01-05 07:37:36', 0, 75, 75, 60, '2026-10-30', 'Percentage'),
    (15, 'SIBLING''S SCHOLARSHIP', 'A Sibling’s Scholarship is for a family with numerous children attending the same institution. These scholarships promote inclusivity and continuity within the school environment by supporting siblings and encouraging family members to pursue their educational ambitions within the same educational community.', '2026-04-30', 'Siblings’ requirement: Applicant must be part of a family with three or more siblings currently enrolled in our institution. (Only one can avail the scholarship)

Academic Requirement: To be considered academically qualified, the applicant must maintain good academic standing, with a general weighted average (GWA) of at least 85%.', '1. Report Card/Transcript Records (Scan the Report Card front and back)
2. Certificate of Enrollment or Registration for each sibling who is currently enrolled in our institution. (PDF File)
3. Certificate of Indigency or Low Income (PDF File)

Note: All required documents must be uploaded as clear, legible copies in PDF format.', 'The students may enjoy 70% discounts on tuition fees equivalent to 21 units. If the student exceeds the maximum subject load per semester, he/she will shoulder the excess tuition fee.

Note: The tuition fee discount shall apply to tuition fees only and shall be effective for the applicable enrollment period, subject to institutional policies.', 5, 'Siblings’ scholarship', 1, 0, '70.00', 'active', '2026-01-05 07:44:24', 0, 75, 75, 60, '2026-10-30', 'Percentage'),
    (16, 'STUDENT SUPREME COUNCIL (SSC) SCHOLARSHIP', 'The Davao Vision Colleges, Inc. Supreme Student Council Scholarship is established to recognize and reward the leadership, dedication, and academic excellence of members of a school''s Supreme Student Council (SSC). This scholarship aims to support students who have demonstrated outstanding contributions to student governance while maintaining high academic standing.', '2026-01-10', 'SSC Membership / Leadership Status: 
Must be a duly elected or appointed officer or active member of the Supreme Student Council (SSC) during the term of application.

Academic Requirement: 
The applicant must maintain good academic standing, with no grade lower than 85% in any subject, and a general weighted average (GWA) of at least 91%.

Compliance with School Policies:
 Must comply with all institutional rules, regulations, and scholarship guidelines.

Good Moral Character: 
Must exhibit good conduct, discipline, and ethical behavior, both inside and outside the campus.

Active Participation: 
Must actively participate in SSC meetings, programs, and school activities.

Enrollment Status: Must be enrolled as a regular or full-time student during the semester the scholarship is granted.', '1. Certificate of Grades
2. Certificate of Good Moral Character
3. Certificate of Appointment
4. Endorsement letter from the Office of Student Affairs (OSA)
5. Certificate of Enrollment or Registration', 'The SSC president and vice president can avail 100% of the scholarship in tuition fees, and the secretary to representatives can also avail 60% of the scholarship, equivalent to 21 units. If the student exceeds the maximum subject load per semester, he or she will shoulder the excess tuition fee.', 20, 'SSC officer scholarship', 1, 0, '100.00', 'archived', '2026-01-05 07:46:35', 0, 75, 75, 60, '2026-02-28', 'Percentage'),
    (17, 'PUBLIC SERVANT''S CHILD SCHOLARSHIP', 'The Public Servant’s Child Scholarship is designed to support the educational goals of students whose parents are employed as local government officials or public servants. This scholarship recognizes the important contributions of public service to society and aims to provide financial assistance to the children of these individuals. By reducing the financial burden of education, the scholarship enables beneficiaries to focus on their studies, develop their full potential, and achieve academic success.', '2026-04-30', 'Financial Need: A student considered financially challenged when neither his or her parents nor his guardian have sufficient resources to finance his/her higher education, through a duly certified statement of monthly income. 

Relationship Status:  The students are must be the son/daughter of the local government officials.
                                 If the students are not the children of a local government official, the LGU can also endorse a student to apply for  this scholarship.

Academic Requirement: To be considered academically qualified, the applicant must maintain good academic standing, with a general weighted average (GWA) of at least 85%.

Good Moral Character: Must have no record of major disciplinary offenses.

Enrollment Status: Must be enrolled as a regular or full-time student during the semester the scholarship is granted.', '1. Latest Report Card/Transcript of Records (Scan the Report Card front and back)
2. Certificate of Good Moral Character (PDF File)
3. Endorsement letter from the barangay (PDF File)
4. Parent/Guardian Employment: (PDF File)
        Certificate of Employment (if applicable)
5. Certificate of Low Income (PDF File)

Note: All required documents must be uploaded as clear, legible copies in PDF format.', 'The dependent may enjoy 70% discounts on tuition fees equivalent to 21units. If the student exceeds the maximum subject load per semester, he/she will shoulder the excess tuition fee.

Note: The tuition fee discount shall apply to tuition fees only and shall be effective for the applicable enrollment period, subject to institutional policies.', 10, 'Academic scholarship', 1, 0, '70.00', 'active', '2026-01-05 08:04:28', 0, 75, 75, 60, '2026-10-30', 'Percentage'),
    (18, 'PASTORAL KID SCHOLARSHIP (PK)', 'The Pastoral Kid Scholarship is to support the education of children whose parents are pastors or ministers. This scholarship aims to help the students achieve their educational goals.', '2026-04-30', 'Parent/Guardian Employment:  The applicant must be the child of a pastor or duly recognized church minister.

Academic Requirement: To be considered intellectually capable, the applicant must possess good academic standing with a general weighted average (85%)

Good Moral Character: Must demonstrate integrity, respect, and exemplary behavior both in school and within the church community.

Enrollment Status: Must be enrolled as a regular or full-time student during the semester the scholarship is granted.', '1. Report Card/Transcript of Records (Scan the Report Card front and back)
2. Certificate of Good Moral Character (PDF File) 
3. Proof of parent’s pastoral role: Church Appointment Letter (PDF File)
4. Recommendation letter from the church head or head pastor (PDF File)
5. Certificate of Low Income (PDF File)

Note: All required documents must be uploaded as clear, legible copies in PDF format.', 'The Pastoral kid may enjoy 70% discounts on tuition fees equivalent to 21 units. If the student exceeds the maximum subject load per semester, he/she will shoulder the excess tuition fee.

Note: The tuition fee discount shall apply to tuition fees only and shall be effective for the applicable enrollment period, subject to institutional policies.', 10, 'Pastors Kids', 1, 0, '70.00', 'active', '2026-01-05 08:24:33', 0, 75, 75, 60, '2026-10-30', 'Percentage'),
    (19, 'YOUTH CHURCH LEADER SCHOLARSHIP (YCL)', 'The Youth Church Leader Scholarship is a program created to support young people who have demonstrated leadership in their church communities. This scholarship is to help the young church leader to pursue their educational goals.', '2026-04-30', 'Leadership Role: Must currently hold a recognized leadership position in the church’s youth ministry (e.g., youth officer, choir leader, ministry coordinator, Bible study leader).

Academic Requirement: To be considered academically qualified, the applicant must maintain good academic standing, with a general weighted average (GWA) of at least 85%.

Enrollment Status: Must be enrolled as a regular or full-time student during the semester the scholarship is granted.

Good Moral Character: Must have no record of major disciplinary offenses.', '1. Latest Report Card / Transcript of Records (Scan the Report Card front and back)
2. Certificate of Good Moral Character (PDF File)
3. Recommendation Letter from the Youth Pastor, Church Pastor, or Ministry Leader confirming leadership role and active involvement. (PDF File)
4. Certificate of Low Income (PDF File)

Note: All required documents must be uploaded as clear, legible copies in PDF format.', 'The student may enjoy 70% discounts on tuition fees equivalent to 21 units. If the student exceeds the maximum subject load per semester, he/she will shoulder the excess tuition fee.

Note: The tuition fee discount shall apply to tuition fees only and shall be effective for the applicable enrollment period, subject to institutional policies.', 10, 'Church leaders', 1, 0, '70.00', 'active', '2026-01-05 08:27:04', 0, 75, 75, 60, '2026-10-30', 'Percentage'),
    (20, 'DVC Varsity', 'The DVC Varsity Scholarship is given to outstanding student athletes who excel at their chosen sports while maintaining good academic standards. This scholarship recognizes their dedication to both athletics and academics while representing the school in varsity level competition.', '2026-01-09', '- The Applicants must be actively involved in varsity-level sports team recognized our institution.
 - Academic Requirement: To be considered intellectually capable, the applicant must possess good academic standing (no grade below 85%) and with general weighted average (85%)
 - The athlete goes through a screening/tryout administered by the respective coach and trainer.
 - Be physically and psychologically fit to play.
 - Good moral character and has never been subjected to any disciplinary action.', '1.	Officially Enrolled in Davao Vision Colleges, Inc.
2.	Recommendation letter from the sports Coordinator noted by OSAD.
3.	Application Form', 'The athlete may enjoy 70% discounts on tuition fees equivalent to 21 units. If the student exceeds the maximum subject load per semester, he/she will shoulder the excess tuition fee.', 0, 'Student assistant', 1, 1, '0.00', 'archived', '2026-01-05 08:36:46', 0, 75, 75, 60, '2026-01-30', 'Peso'),
    (21, 'INSTITUTIONAL SCHOLARSHIP', 'The Institutional Scholarship supports students who need financial assistance and are dedicated to completing their education. This scholarship provides a fifty percent (50%) discount on the tuition fee to support deserving students who may face financial challenges. Through this scholarship, the student will reduce the financial burden of their education, allowing them to focus on their academics, personal development, and completing their program.', '2026-04-30', 'Financial Need: A student is considered financially challenged when neither his or her parents nor his guardian has sufficient resources to finance his/her higher education, through a duly certified statement of monthly income. 

Academic Requirement: To be considered academically qualified, the applicant must maintain good academic standing, with a general weighted average (GWA) of at least 85%.

Enrollment Status: Must be enrolled as a regular or full-time student during the semester the scholarship is granted.

Good Moral Character: Must have no record of major disciplinary offenses.', '1. Latest Report Card / Transcript of Records (Scan the report card front and back)
2. Certificate of Low Income (PDF File)
3. Certificate of Good Moral Character (PDF File)
4. Certificate of GWA (for transferee students) (PDF File)

Note: All required documents must be uploaded as clear, legible copies in PDF format.', 'The students may enjoy 50% discounts on tuition fees equivalent to 21 units. If the student exceeds the maximum subject load per semester, he/she will shoulder the excess tuition fee.

Note: The tuition fee discount shall apply to tuition fees only and shall be effective for the applicable enrollment period, subject to institutional policies.', 80, 'Student assistant', 1, 0, '50.00', 'active', '2026-01-05 08:50:30', 0, 75, 75, 60, '2026-10-30', 'Percentage'),
    (22, 'SHS SCHOLARSHIP (NON-VOUCHER)', 'The SHS Scholarship is to support students based on various criteria, such as academics achievement, extracurricular involvement, or financial need. This scholarship aims to support students in pursuing their studies.', '2026-04-30', 'Financial Need: A student considered financially challenged when neither his or her parents nor his guardian have sufficient resources to finance his/her higher education, through a duly certified statement of monthly income. 

Academic Requirement: To be considered intellectually capable, the applicant must possess good academic standing with a general weighted average of at least 85%', '1. Report Card	
2. Certificate of Good Moral Character
3. Certificate of Indigency or Low Income
4. Recommendation letter from the School Principal', 'The students may enjoy 50% discounts on tuition fees if he/she not a government voucher grantee.

Note: The tuition fee discount shall apply to tuition fees only and shall be effective for the applicable enrollment period, subject to institutional policies.', 10, 'DVC senior High Graduates', 1, 0, '50.00', 'active', '2026-01-05 08:54:38', 0, 75, 75, 60, '2026-10-30', 'Percentage'),
    (24, 'YEOMCHANG SCHOLARSHIP (THEOLOGY STUDENTS ONLY)', 'The Yeomchang Scholarship is supported by the Yeomchang Central Presbyterian Church, located in South Korea. This scholarship aims to support students who need financial support for their studies not only theology students but all the students in the department who have demonstrated outstanding contributions to maintaining high academic standing.', '2026-04-30', 'Financial Need: A student considered financially challenged when neither his or her parents nor his guardian have sufficient resources to finance his/her higher education, through a duly certified statement of monthly income. 

Academic Requirement: To be considered academically qualified, the applicant must maintain good academic standing, with a general weighted average (GWA) of at least 85%.

Enrollment Status: Must be enrolled as a regular or full-time student during the semester the scholarship is granted.

Good Moral Character: Must have no record of major disciplinary offenses.

Non-Duplication of Scholarship: The applicant must not be a recipient of any other scholarship outside the institution.', '1. Latest Report Card / Transcript of Records/Student Permanent Record ((Scan the report card front and back)
2. Certificate of Good Moral Character duly signed by the Prefect of Discipline (POD) or Guidance Counselor (PDF File)
3. Recommendation letter from the Program head (PDF File)
4. Recommendation letter from the host pastor of the applicant’s church (for Theology Department applicants only). (PDF File)
5. Certificate of Low Income (PDF File)

Note: All required documents must be uploaded as clear, legible copies in PDF format.', 'All YEOMCHANG scholars can avail of the highest financial subsidies, up to ten thousand pesos (10,000.00), equivalent to 21 units only across the programs. If the student enrolls beyond 21 units, he or she has to pay for the excess units. Supplemental fees are not included in this benefit and thus will be shouldered by the student personally. The dormitory shall be evaluated upon the need of the student.', 60, 'Yeomchang Scholarship', 1, 0, '10000.00', 'active', '2026-01-05 17:34:03', 0, 75, 75, 60, '2026-10-30', 'Peso'),
    (25, 'STUDENT ASSISTANT SCHOLARSHIP', 'The Student Assistant is expected to assist the department or office in all activities inherent to the official tasks. The student assistant shall accept clerical, messengerial, and ministerial tasks pertinent to the needs of the department and other tasks that the departmental head may assign.', '2026-04-30', 'Financial Need: A student considered financially challenged when neither his or her parents nor his guardian have sufficient resources to finance his/her higher education, through a duly certified statement of monthly income. 

Academic Requirement: To be considered intellectually capable, the applicant must possess good academic standing (no grade below 85% per subject) and with general weighted average of at least 85%

Good Moral Character: Must have no record of major disciplinary offenses.', '1. Latest Report Card / Transcript of Records	
2. Certificate of Good Moral Character duly signed by the Prefect of Discipline (POD)
3. Certificate of Indigency
4. Medical Certificate (physically fit for work as certified by duly licensed physician).
5. Recommendation Letter from the Program Head or Program Coordinator
6. Signed Student Assistant Contract / Agreement', '- All Student Assistants (SAs) may enjoy 80% discounts on tuition fees equivalent to 21 units and miscellaneous fees. Supplemental fees are not included in this benefit and thus will be shouldered by the student assistant personally. If an SA is enrolled beyond 21 units, he/she has to pay for the excess units.

- All Student Assistants may also receive an allowance of 3,000.00 per month.

Note: The tuition fee discount shall apply to tuition fees only and shall be effective for the applicable enrollment period, subject to institutional policies', 7, 'Student assistant', 1, 0, '80.00', 'archived', '2026-01-05 19:02:37', 0, 75, 75, 60, '2026-10-30', 'Percentage'),
    (26, 'TEACHER''S KID SCHOLARSHIP', 'A Teacher''s Kid Scholarship aims to support the educational goals of students who are the children of teachers. This scholarship acknowledges the valuable contributions that teachers make to society and aims to provide assistance to their children in achieving their academic goals. The Teacher''s Kid scholarship recognizes the dedication and hard work of teachers and seeks to ease the financial burden for their children, allowing them to focus on their studies and achieve academic success.', '2026-04-30', 'Relationship Status:  The scholarship is must be the son/daughter of the teacher.

Academic Requirement: To be considered intellectually capable, the applicant must possess good academic standing with a general weighted average (85%)

Good Moral Character: Must have no record of major disciplinary offenses.

Enrollment Status: Must be enrolled as a regular or full-time student during the semester the scholarship is granted.', '1. Report Card/Transcript of Records (Scan the report card front and back)
2. Certificate of Good Moral Characteristics (PDF File)
3. Proof of the Parent’s Employment as a Teacher, which may be any one (1) of the following: (PDF File)
          3.1 Certificate of Employment (COE)
          3.2 Valid School Identification Card of the parent
          3.3 Latest Service Record (if applicable)

Note: All required documents must be uploaded as clear, legible copies in PDF format.', 'The Teacher’s kid may enjoy 70% discounts on tuition fees equivalent to 21 units. If the student exceeds the maximum subject load per semester, he/she will shoulder the excess tuition fee.

Note: The tuition fee discount shall apply to tuition fees only and shall be effective for the applicable enrollment period, subject to institutional policies.', 10, 'Public teachers’ workers', 1, 0, '70.00', 'active', '2026-01-05 19:06:48', 0, 75, 75, 60, '2026-10-30', 'Percentage'),
    (27, 'HOPE SCHOLARSHIP', 'The HOPE Scholarship (Helping Our Pupil Education) is a financial assistance program established to support deserving and financially challenged students in pursuing quality education at Davao Vision Colleges. This scholarship embodies the institution’s commitment to extending opportunities to learners who demonstrate determination, potential, and a strong desire to succeed despite economic limitations.

The HOPE Scholarship aims to ease the financial burden of education by providing tuition fee assistance to qualified students. It is granted to individuals who exhibit good academic standing, moral integrity, and a willingness to uphold the values and standards of the institution.

Through the HOPE Scholarship, Davao Vision Colleges strengthens its mission of empowering students, fostering academic growth, and transforming lives through accessible and compassionate educational support.

The program reflects the belief that education is a powerful instrument of hope, capable of shaping brighter futures for students, families, and communities.', '2026-03-31', 'The HOPE Scholarship is exclusively available to Fourth Year (4th Year) students who meet the following qualifications:

Year Level Requirement: Must be a currently enrolled Fourth Year student of Davao Vision Colleges during the semester of application.

Academic Standing: Must maintain good academic performance, with no failing grades and a general weighted average (GWA) of at least 85%.
                           
Good Moral Character: Must have no record of major disciplinary offenses.
                                      Must uphold the values and standards of the institution.

Enrollment Status: Must be enrolled as a regular or full-time student during the semester the scholarship is granted.

Financial Need: May be required to demonstrate financial need, subject to evaluation by the Scholarship Committee.', '1. Recommendation letter from the Program Head
2. Certificate of Good Moral Character duly signed by the Prefect of Discipline (POD)
3. Student Permanent Record
4. Certificate of Indigency or Low Income', 'Financial Assistance Grant:
       A fixed amount of Five Thousand Pesos (₱5,000.00) per semester.
       The amount shall be applied to the student’s tuition and other school fees, as determined by the Accounting Office.

Financial Relief:
      Reduction of financial burden on students and their families, allowing scholars to focus on their academic performance.

Renewal Opportunity: 
      The scholarship may be renewed per semester, subject to compliance with academic and retention requirements.', 8, 'Employees immediate family', 1, 0, '5000.00', 'archived', '2026-02-12 01:27:12', 0, 75, 75, 60, NULL, 'Peso');

