INSERT INTO "application_responses" ("id", "application_id", "form_field_id", "response_value") VALUES
    (4953, 382, 276, 'I believe I deserve this scholarship because I have consistently shown dedication to my studies and a strong commitment to personal and academic growth. Maintaining a high level of academic performance has always been important to me, and I have worked hard to achieve grades that reflect my discipline, perseverance, and passion for learning. With a General Weighted Average that meets the scholarship requirement and with no grades falling below the standard, I have proven my ability to excel even when faced with challenges.
Beyond academics, I value good character just as much as good performance. I strive to uphold integrity, respect, and responsibility in everything I do, both inside and outside the classroom. I understand that being a scholar is not only about achieving high grades but also about maintaining a positive attitude, demonstrating leadership, and showing a willingness to contribute to the school community.
Receiving this scholarship will greatly support my educational journey. As a full-time student, it will allow me to focus more on my studies and lessen the financial burden on my family. It will motivate me to maintain excellent academic standing and continue working hard to reach my goals. Most importantly, this scholarship will serve as an opportunity for me to grow, excel, and give back by becoming a responsible and productive member of the institution.
I am committed to upholding the standards of this scholarship and proving that I am worthy of this investment in my future. With your support, I am confident that I can continue striving for excellence and use my education to make a positive impact.'),
    (4954, 382, 277, '2021 - 2024'),
