    (2, 64, 34, '2026-01-05 08:22:47', '2nd Year', 'BSIT', '26', '91.64', '09564325750', '1995-06-01', 'Pala pag Northern samar', '30', 'Prk. 5A CEBUDA brgy Bago oshiro ', 'Prk. 5A CEBUDA brgy Bago oshiro ', 'None', 'Lea Fuentes ', 'Housewife ', '09564325750', 'Roble Fuentes ', 'Driver', '09564325750', '5000', 'No', 'No', 'Sapian national high school ', 'N/A', 'Davao Vision Colleges Inc ', '2nd year ', 'This scholarship helps me pay for school so I can focus on my studies. It gives me the support I need to graduate and reach my goals.', '2009 - 2013', '00 - 00'),
    (3, 65, 30, '2026-01-05 08:27:58', '3rd Year', 'AB-THEO', '24', '88', '09127897574', '2004-10-13', 'Anonang Bansalan Davao delsur ', '21', 'Prk 3 Alcantara Gumalang Baguio District Davao City ', 'Prk 3 Alcantara Gumalang Baguio District Davao City ', 'Bagobo klata ', 'Loreza Pandayan ', 'Housewife ', '09127897574', 'Harrizon Pandayan ', 'Laborer ', '09127897574', '6000', 'No', 'No', 'Elias P Dacudao Gumalang School of home ', 'Elias P Dacudao Gumalang School of home ', 'Davao Vision College ', '3rd Year Ab-Theology ', 'With God’s guidance, I work hard in my studies and hope to use this scholarship to build a better future and serve others.', '2019 - 2020', '2021 - 2022'),
