    (5, 67, 27, '2026-01-05 08:44:30', '3rd Year', 'AB-THEO', '24', '85', '09155413251', '2002-11-19', 'Panipasan marilog district Davao City', '23', 'Davao City', 'Davao City', 'Belaan', 'Divina M. Lumbay', 'House wife', '09155414251', 'Fernando S. Lumbay', 'Driver', '0950 430 9863', '4,000', 'No', 'No', 'Leon Grace national high school', 'Leon Grace national high school', 'DVC', '3 year', 'I deserve this scholarship because I went to help my family and other''s. ', '2018 - 2021', '2021 - 2022'),
    (6, 68, 32, '2026-01-05 08:46:33', '3rd Year', 'BSIT', '24', '93.71', '09617379530', '2003-02-10', 'Mandug City', '22', 'SGR Village Catalunan Grande Davao City', 'SGR Village Catalunan Grande Davao City', 'Not part of an indigenous group', 'Cristine Pelaez', 'House Wife', '09091795287', 'Anastacio Manliguez', 'Cybersecurity', '09078055216', '25000', 'no', 'no', 'Jesus J. Soriano National High School', 'Jesus J. Soriano National High School', 'Davao Vision Colleges, Inc', '3rd Year', 'to reduce the expenses', '2019 - 2020', '2021 - 2022'),
    (7, 69, 24, '2026-01-05 09:13:44', '3rd Year', 'BSED- ENGLISH', '27', '96', '09055824143', '2004-10-04', 'Davao City', '21', 'Stone Rock Village, Catalunan Grande, Davao City', 'Stone Rock Village, Catalunan Grande, Davao City', 'N/A', 'Grace G. Abuela', 'Housewife', '09691130159', 'Armando C. Abuela', 'Hatchery Aids', '09460062995', '10000', 'No', 'No', 'Jesus J. Soriano National High School', 'Davao Vision Colleges, Inc.', 'Davao Vision Colleges, Inc.', '3rd Year', 'I deserve this scholarship because I am committed to academic excellence, I am motivated to succeed, and the financial support would help me focus on my education and future goals.', '2017 - 2021', '2021 - 2023'),
    (8, 70, 18, '2026-01-05 09:15:49', '3rd Year', 'BSIT', '24', '93', '09271511392', '2003-09-13', 'Quezon City ', '22', 'Caflor Village Pearl Street Catalunan Grande ', 'Caflor Village Pearl Street Catalunan Grande ', 'None', 'Nilda Talero', 'Housewife', '09957542595', 'Alberto Igalan', 'Driver', '09772371955', '5000', 'No', 'No', 'Jesus J. Soriano National High school ', 'Shepherd Mylambs Christian College ', 'Davao Vision College Inc.', 'Third Year', 'I believe I deserve this scholarship because I work hard, stay committed to my studies, and want to create a better future for myself and my family. This support would ease my financial stress and help me stay focused on reaching my goals and giving back to others.', '2017 - 2021', '2021 - 2023'),
    (9, 71, 21, '2026-01-05 09:28:53', '3rd Year', 'BSED- ENGLISH', '27', '94.3', '09055824143', '2004-07-03', 'Davao City', '21', 'Purok 3-A Biao Joaquin, Calinan, Davao City', 'Purok 3-A Biao Joaquin, Calinan, Davao City', 'Obo Manobo', 'Nenita B. Alboroto', 'Housewife', '09161959223', 'Alejandro M. Alboroto', 'Laborer', '09074236352', '5000', 'No', 'No', 'Calinan National High School', 'Calinan National High School', 'Davao Vision Colleges', '3rd Year', 'I deserve this scholarship because I am committed to my education, work hard to achieve my goals, and plan to use this opportunity to make a positive impact in my community.', '2017 - 2021', '2021 - 2023'),
    (10, 72, 37, '2026-01-05 10:11:18', '2nd Year', 'BSIT', '26', '89.75', '09387080745', '2006-08-05', 'Davao City ', '19', 'Prk 1-B Lamanan Calinan Davao City ', 'Prk 1-B Lamanan Calinan Davao City ', 'None ', 'Elsie P. Pernia ', 'House wife ', '09103503925', 'Rolando T. Pernia', 'Laborer ', '09103503925', '5000', 'No', 'No', 'Lamanan National High School ', 'Lamanan National High School ', 'Davao Vision Colleges, Inc', '2nd Year ', 'I deserve this scholarship because I want to finish my study and my parents can''t fully support me because of the financial problem. ', '2018 - 2022', '2022 - 2024'),
