INSERT INTO "scholarship_submissions_13" ("id", "application_id", "student_id", "submitted_at", "year_level", "program", "units_enrolled", "gwa", "contact_number", "birthdate", "birthplace", "age", "permanent_address", "current_address", "tribe", "mother_name", "mother_occupation", "mother_contact", "father_name", "father_occupation", "father_contact", "parents_income", "is_working_student", "is_pwd", "jhs_school", "shs_school", "current_school", "current_year_level", "essay_motivation", "jhs_year", "shs_year") VALUES
    (1, 382, 287, '2026-04-06 22:41:44', '1st Year', 'BSED-MATH', '15', '94', '09069180200', '2007-11-18', 'Davao City', '18', '98-3 Bonifacio St. Davao City ', '98-3 Bonifacio St. Davao City ', '', 'Maria Theresa Tindoy Modio', 'Cleaner', '09069180200', 'NA', '', '', '16000', 'No', 'No', 'Davao City National High School ', 'Davao City National High School ', 'Davao City National High School ', '12', 'I believe I deserve this scholarship because I have consistently shown dedication to my studies and a strong commitment to personal and academic growth. Maintaining a high level of academic performance has always been important to me, and I have worked hard to achieve grades that reflect my discipline, perseverance, and passion for learning. With a General Weighted Average that meets the scholarship requirement and with no grades falling below the standard, I have proven my ability to excel even when faced with challenges.
Beyond academics, I value good character just as much as good performance. I strive to uphold integrity, respect, and responsibility in everything I do, both inside and outside the classroom. I understand that being a scholar is not only about achieving high grades but also about maintaining a positive attitude, demonstrating leadership, and showing a willingness to contribute to the school community.
Receiving this scholarship will greatly support my educational journey. As a full-time student, it will allow me to focus more on my studies and lessen the financial burden on my family. It will motivate me to maintain excellent academic standing and continue working hard to reach my goals. Most importantly, this scholarship will serve as an opportunity for me to grow, excel, and give back by becoming a responsible and productive member of the institution.
I am committed to upholding the standards of this scholarship and proving that I am worthy of this investment in my future. With your support, I am confident that I can continue striving for excellence and use my education to make a positive impact.', '2021 - 2024', '2024 - 2026'),
    (2, 383, 289, '2026-04-07 08:38:25', '1st Year', 'BEED', '23', '93', '09854583180', '2008-08-08', 'Los Amigos Tugbok Davao City ', '18', 'Purok 10 Sarro Manuel Guianga Tugbok Davao City ', 'Purok 10 Sarro Manuel Guianga Tugbok Davao City ', '', 'Michelle Caballes', '', '09515257871', 'N/A', '', '', '5000', 'No', 'No', 'Bartolome Integrated School', 'Calinan National High School ', 'Calinan National High School ', '12 ', 'I believe I deserve this scholarship because I am a committed and hardworking student who always tries my best. This opportunity is not only a dream of mine but also of my parents, who have supported me along the way. With this scholarship, I hope to continue learning, achieving my goals, and giving back to my parents, making their support truly meaningful.', '2020 - 2024', '2024 - 2026'),
    (3, 386, 294, '2026-04-08 12:50:53', '1st Year', 'AB-THEO', '3', '90', '09639182849', '2007-10-27', 'Davao City ', '18', 'Prk. 7 Pictan Cadalian Baguio District ', 'Prk. 7 Pictan Cadalian ', 'Bagobo Klata', 'Jocelyn Addy Guzon', 'Domestic Helper', '09095908230 ', 'Bonnie Vergara Guzon', 'Construction Worker ', '09095908230', '2000', 'No', 'No', 'Baguio National School of Arts And Trades', 'Baguio National School of Arts And Trades ', 'Baguio National School of Arts and Trades', 'Grade 12', 'My GWA is 90 above and I''m a consistent with honors during my senior high school journey ', '2024 - 2025', '2025 - 2026');

