    (102, 185, 71, '2026-01-07 08:08:00', '3rd Year', 'BSED- ENGLISH', '27', '90.44', '09265877002', '2003-09-03', NULL, '22', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
    (103, 186, 62, '2026-01-07 08:21:10', '2nd Year', 'BSED- ENGLISH', '26', '91', '985 045 7543 ', '2005-10-28', 'Davao City', '20', 'Purok-7 Bualan Catigan Toril Davao City ', 'Purok-7 Bualan Catigan Toril Davao City', 'Bagobo Tagabawa', 'Jeneffer Antal ', 'House Wife ', '09550741798', 'Ronnie Antal ', 'Farmer ', '09168243009', '5000', 'No', 'No', 'Catigan National High School ', 'Marhaba School of Davao Inc.', 'Davao vision colleges inc. ', '2nd-year ', 'I deserve this scholarship because I am a student mother who is determined to pursue education despite the many challenges I face. Balancing my responsibilities as a parent and as a student requires discipline, sacrifice, and strong time management skills. Even with limited resources, I continue to strive for academic excellence because I believe education is the key to building a better future for my child and myself.
This scholarship would greatly help ease my financial burden and allow me to focus more on my studies while providing for my family. More than financial support, it would serve as motivation for me to continue working hard and to become a role model for my child—showing that perseverance, education, and determination can overcome any obstacle. With this opportunity, I am committed to finishing my education and giving back to my community in the future.', '2018 - 2022', '2022 - 2024', NULL, NULL),
    (104, 187, 52, '2026-01-07 08:41:38', '2nd Year', 'BSIT', '26', '1.50', '', '2006-08-07', NULL, '19', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
    (105, 188, 39, '2026-01-07 08:45:33', '2nd Year', 'BEED', '29', '92.8', '09164622904', '2005-12-16', 'Davao City', '20', 'Purok 15. Bula Catalunan Grande Davao City', 'Purok 15. Bula Catalunan Grande Davao City', 'N/A', 'Ma. Josie J. Cañete', 'Housewife', '09436144623', 'Teofisto Jr. V. Cañete', 'Tricyle Driver', '09164622904', '3000', 'No', 'No', 'Jesus J. Soriano National Highschoo', 'Davao Vision Colleges, Inc.', 'Davao Vision Colleges, Inc.', '2nd Year', 'It is because of that, my family is not able to support me through financial, and I am afraid that I''m not able to continue my studies here at DVC. So, I take this opportunity to be able to continue my journey as a DVC''ian. Furthermore, I deserve this chance to be part of a Yeaomchang scholar, and I promise that I will work hard, study hard, learn hard, and at the same time I will contribute to our school to be an active student in all school activities.', '2018 - 2021', '2022 - 2023', NULL, NULL),
