    (132, 238, 56, '2026-01-08 13:40:44', '1st Year', 'AB-THEO', '23', '89.93', '09055869302', '2004-05-18', 'Taboc camaligbato Danao City cebu ', '21', 'Phase3 block22 lot15 Decahomestugbok ', 'Phase3 block22 lot15 Decahomestugbok ', 'Bisaya', 'Maridel Hamaguchi ', 'House wife/pastor ', '', 'Jimmy Hamaguchi ', 'Construction worker ', '', '10000', 'No', 'No', 'G. Astilla Sr. Cultural Minority High school ', 'G.Astilla Sr. cultural Minority High school ', 'Davao Vision college ', '1st year ', 'Why I Deserve This Scholarship
 
